python3 -c "
import json,collections
d=json.load(open('/mnt/d/ClaudeProjects/NOLAN/projects/homer/scene_plan.json'))
scenes=[s for v in d['sections'].values() for s in v]
print('sections',len(d['sections']),'scenes',len(scenes))
allowed={'id','start','duration','narration_excerpt','visual_type','visual_description','search_query','comfyui_prompt'}
vt=collections.Counter(s['visual_type'] for s in scenes); print(dict(vt))
for s in scenes:
    if set(s)-allowed: print('BAD FIELD',s['id'],set(s)-allowed)
    if 'search_query' in s and s['visual_type']!='b-roll': print('SQ non-broll',s['id'])
    if 'comfyui_prompt' in s and s['visual_type']!='generated-image': print('CP non-gen',s['id'])
    if s['visual_type']=='b-roll' and 'search_query' not in s: print('broll no sq',s['id'])
    if s['visual_type']=='generated-image' and 'comfyui_prompt' not in s: print('gen no cp',s['id'])
ids=[s['id'] for s in scenes]; print('unique ids',len(set(ids))==len(ids))
# consecutive check
prev=None;run=0;bad=False
for s in scenes:
    if s['visual_type']==prev: run+=1
    else: run=1; prev=s['visual_type']
    if run>2: print('RUN>2 at',s['id']); bad=True
print('consecutive ok',not bad)
# total duration
def tosec(t): m,sec=t.split(':'); return int(m)*60+int(sec)
tot=sum(int(s['duration'].rstrip('s')) for s in scenes); print('total dur',tot)
# verify start=cumulative
c=0
for s in scenes:
    if tosec(s['start'])!=c: print('START MISMATCH',s['id'],s['start'],c)
    c+=int(s['duration'].rstrip('s'))
print('end',c)
"
